#!/usr/bin/env python3
"""AirBench 94 baseline with a CLI and JSON output contract."""

from __future__ import annotations

import argparse
import json
import os
import random
from math import ceil
from pathlib import Path

import torch
import torch.nn.functional as F
from torch import nn


torch.backends.cudnn.benchmark = True
try:
    torch.set_float32_matmul_precision("high")
except Exception:
    pass


def _safe_torch_load(path: str | os.PathLike[str], map_location: torch.device | str):
    try:
        return torch.load(path, map_location=map_location, weights_only=True)
    except TypeError:
        return torch.load(path, map_location=map_location)


@torch.compile
def zeropower_via_newtonschulz5(G, steps=3, eps=1e-7):
    assert len(G.shape) == 2
    a, b, c = (3.4445, -4.7750, 2.0315)
    X = G.bfloat16()
    X /= X.norm() + eps
    if G.size(0) > G.size(1):
        X = X.T
    for _ in range(steps):
        A = X @ X.T
        B = b * A + c * A @ A
        X = a * X + B @ X
    if G.size(0) > G.size(1):
        X = X.T
    return X


class Muon(torch.optim.Optimizer):
    def __init__(self, params, lr=1e-3, momentum=0, nesterov=False):
        if lr < 0.0:
            raise ValueError(f"Invalid learning rate: {lr}")
        if momentum < 0.0:
            raise ValueError(f"Invalid momentum value: {momentum}")
        if nesterov and momentum <= 0:
            raise ValueError("Nesterov momentum requires a momentum")
        defaults = dict(lr=lr, momentum=momentum, nesterov=nesterov)
        super().__init__(params, defaults)

    @torch.no_grad()
    def step(self):
        for group in self.param_groups:
            lr = group["lr"]
            momentum = group["momentum"]
            for p in group["params"]:
                g = p.grad
                if g is None:
                    continue
                state = self.state[p]
                if "momentum_buffer" not in state:
                    state["momentum_buffer"] = torch.zeros_like(g)
                buf = state["momentum_buffer"]
                buf.mul_(momentum).add_(g)
                g = g.add(buf, alpha=momentum) if group["nesterov"] else buf
                p_norm = p.data.norm()
                if torch.isfinite(p_norm) and p_norm > 0:
                    p.data.mul_(len(p.data) ** 0.5 / p_norm)
                update = zeropower_via_newtonschulz5(g.reshape(len(g), -1)).view(g.shape)
                p.data.add_(update, alpha=-lr)


CIFAR_MEAN = torch.tensor((0.4914, 0.4822, 0.4465), dtype=torch.float32)
CIFAR_STD = torch.tensor((0.2470, 0.2435, 0.2616), dtype=torch.float32)


def batch_flip_lr(inputs):
    flip_mask = (torch.rand(len(inputs), device=inputs.device) < 0.5).view(-1, 1, 1, 1)
    return torch.where(flip_mask, inputs.flip(-1), inputs)


def batch_crop(images, crop_size):
    r = (images.size(-1) - crop_size) // 2
    shifts = torch.randint(-r, r + 1, size=(len(images), 2), device=images.device)
    images_out = torch.empty((len(images), 3, crop_size, crop_size), device=images.device, dtype=images.dtype)
    if r <= 2:
        for sy in range(-r, r + 1):
            for sx in range(-r, r + 1):
                mask = (shifts[:, 0] == sy) & (shifts[:, 1] == sx)
                images_out[mask] = images[mask, :, r + sy : r + sy + crop_size, r + sx : r + sx + crop_size]
    else:
        images_tmp = torch.empty(
            (len(images), 3, crop_size, crop_size + 2 * r),
            device=images.device,
            dtype=images.dtype,
        )
        for s in range(-r, r + 1):
            mask = shifts[:, 0] == s
            images_tmp[mask] = images[mask, :, r + s : r + s + crop_size, :]
        for s in range(-r, r + 1):
            mask = shifts[:, 1] == s
            images_out[mask] = images_tmp[mask, :, :, r + s : r + s + crop_size]
    return images_out


def set_global_seed(seed: int) -> None:
    random.seed(seed)
    torch.manual_seed(seed)
    if torch.cuda.is_available():
        torch.cuda.manual_seed_all(seed)


def _candidate_data_paths(data_dir: str | os.PathLike[str], train: bool) -> list[Path]:
    root = Path(data_dir)
    stem = "train" if train else "test"
    names = [
        f"{stem}.pt",
        f"cifar10_{stem}.pt",
        f"{stem}.pth",
        f"cifar10_{stem}.pth",
    ]
    return [root / name for name in names]


def _extract_images_labels(data) -> tuple[torch.Tensor, torch.Tensor]:
    if isinstance(data, dict):
        image_keys = ("images", "x", "inputs")
        label_keys = ("labels", "y", "targets")
        images = next((data[k] for k in image_keys if k in data), None)
        labels = next((data[k] for k in label_keys if k in data), None)
        if images is None or labels is None:
            raise KeyError("Could not find images/labels in loaded CIFAR tensor file")
        return torch.as_tensor(images), torch.as_tensor(labels)
    if isinstance(data, (tuple, list)) and len(data) == 2:
        return torch.as_tensor(data[0]), torch.as_tensor(data[1])
    raise TypeError(f"Unsupported CIFAR tensor payload type: {type(data)!r}")


def _load_cifar_tensors(data_dir: str, train: bool, device: torch.device) -> tuple[torch.Tensor, torch.Tensor]:
    for path in _candidate_data_paths(data_dir, train):
        if path.exists():
            payload = _safe_torch_load(path, map_location=device)
            images, labels = _extract_images_labels(payload)
            break
    else:
        split = "train" if train else "test"
        raise FileNotFoundError(f"Could not find CIFAR-10 tensor file for split={split!r} under {data_dir!r}")

    images = images.to(device=device)
    labels = labels.to(device=device, dtype=torch.long)

    if images.ndim != 4:
        raise ValueError(f"Expected images with rank 4, got shape={tuple(images.shape)}")
    if images.shape[1] != 3 and images.shape[-1] == 3:
        images = images.permute(0, 3, 1, 2)
    if images.shape[1] != 3:
        raise ValueError(f"Expected channel dimension of 3, got shape={tuple(images.shape)}")

    images = images.contiguous()
    if images.dtype == torch.uint8:
        images = images.float().div_(255.0)
    else:
        images = images.float()
        if float(images.max().item()) > 1.5:
            images.div_(255.0)

    return images, labels.contiguous()


class CifarLoader:
    def __init__(self, data_dir: str, train: bool, batch_size: int, aug: dict | None = None):
        self.device = torch.device("cuda")
        self.batch_size = int(batch_size)
        self.train = bool(train)
        self.aug = dict(aug or {})

        images, labels = _load_cifar_tensors(data_dir, train=train, device=self.device)
        self.images = images.contiguous(memory_format=torch.channels_last)
        self.labels = labels

        mean = CIFAR_MEAN.to(device=self.device).view(1, 3, 1, 1)
        std = CIFAR_STD.to(device=self.device).view(1, 3, 1, 1)
        self.normalized_images = ((self.images - mean) / std).contiguous(memory_format=torch.channels_last)

    def __len__(self) -> int:
        return (len(self.labels) + self.batch_size - 1) // self.batch_size

    def __iter__(self):
        if self.train:
            indices = torch.randperm(len(self.labels), device=self.device)
        else:
            indices = torch.arange(len(self.labels), device=self.device)

        for batch_idx in range(0, len(indices), self.batch_size):
            idx = indices[batch_idx : batch_idx + self.batch_size]
            inputs = self.normalized_images[idx]
            if self.aug.get("translate", 0):
                pad = int(self.aug["translate"])
                inputs = F.pad(inputs, (pad, pad, pad, pad), mode="reflect")
                inputs = batch_crop(inputs, 32)
            if self.aug.get("flip", False):
                inputs = batch_flip_lr(inputs)
            yield inputs.contiguous(memory_format=torch.channels_last), self.labels[idx]


class ConvBN(nn.Module):
    def __init__(self, in_ch: int, out_ch: int):
        super().__init__()
        self.conv = nn.Conv2d(in_ch, out_ch, kernel_size=3, padding=1, bias=False)
        self.norm = nn.BatchNorm2d(out_ch)
        self.act = nn.GELU()

    def forward(self, x):
        return self.act(self.norm(self.conv(x)))


class Whitening(nn.Module):
    def __init__(self, channels: int = 3):
        super().__init__()
        self.bias = nn.Parameter(torch.zeros(channels, dtype=torch.float32))

    def forward(self, x, whiten_bias_grad: bool = True):
        bias = self.bias.view(1, -1, 1, 1)
        if not whiten_bias_grad:
            bias = bias.detach()
        return x + bias


class CifarNet(nn.Module):
    def __init__(self, width: int = 256, num_classes: int = 10):
        super().__init__()
        self.whiten = Whitening(3)
        self.stem = ConvBN(3, width)
        self.block1 = ConvBN(width, width)
        self.block2 = ConvBN(width, width)
        self.pool = nn.MaxPool2d(2)
        self.block3 = ConvBN(width, width * 2)
        self.block4 = ConvBN(width * 2, width * 2)
        self.block5 = ConvBN(width * 2, width * 2)
        self.head_norm = nn.BatchNorm1d(width * 2)
        self.head = nn.Linear(width * 2, num_classes, bias=False)
        self._init_state = {k: v.detach().cpu().clone() for k, v in self.state_dict().items()}
        self.reset()

    def reset(self):
        state = {k: v.clone() for k, v in self._init_state.items()}
        self.load_state_dict(state, strict=True)
        return self

    @torch.no_grad()
    def init_whiten(self, sample_inputs: torch.Tensor):
        x = sample_inputs.float()
        mean = x.mean(dim=(0, 2, 3))
        self.whiten.bias.copy_(-mean.to(device=self.whiten.bias.device, dtype=self.whiten.bias.dtype))

    def forward(self, x, whiten_bias_grad: bool = True):
        x = self.whiten(x, whiten_bias_grad=whiten_bias_grad)
        x = self.stem(x)
        x = self.block1(x)
        x = self.block2(x)
        x = self.pool(x)
        x = self.block3(x)
        x = self.block4(x)
        x = self.block5(x)
        x = x.mean(dim=(2, 3))
        x = self.head_norm(x)
        return self.head(x)
